var maxValue = function(nums1, nums0) {
    const MOD = 1000000007n;
    function power(base, exp) {
        base = ((base % MOD) + MOD) % MOD;
        let result = 1n;
        while (exp > 0n) {
            if (exp & 1n) result = (result * base) % MOD;
            base = (base * base) % MOD;
            exp >>= 1n;
        }
        return result;
    }
    const n = nums1.length;
    const segs = [];
    for (let i = 0; i < n; i++) segs.push([nums1[i], nums0[i]]);
    const pureOnes = segs.filter(([a, b]) => b === 0 && a > 0);
    const mixed = segs.filter(([a, b]) => a > 0 && b > 0);
    const pureZero = segs.filter(([a, b]) => a === 0);
    mixed.sort((x, y) => (y[0] - x[0]) || (x[1] - y[1]));
    const ordered = pureOnes.concat(mixed, pureZero);
    let val = 0n;
    for (const [a, b] of ordered) {
        const length = BigInt(a + b);
        const segval = ((power(2n, BigInt(a)) - 1n + MOD) % MOD) * power(2n, BigInt(b)) % MOD;
        val = (val * power(2n, length) + segval) % MOD;
    }
    return Number(val);
};
